ee:message.ee:set-payload:
%dw 2.0
output application/json
---
{
  jsonrpc: "2.0",
  id:      vars.rpcId,
  result: {
    protocolVersion: "2025-03-26",
    serverInfo: { name: "atelier-mcp-contract", version: "1.0.0" },
    capabilities: { tools: { listChanged: false } }
  }
}

%dw 2.0
output application/json
var resultBody = payload.result default {}
var isError = (payload.status default "") == "error"
---
{
  jsonrpc: "2.0",
  id:      vars.rpcId,
  result: {
    content: [{ "type": "text", text: write(resultBody, "application/json") }],
    isError: isError
  }
}

%dw 2.0
output application/json
---
{
  jsonrpc: "2.0",
  id:      vars.rpcId,
  error:   { code: -32601, message: "Method not found: " ++ (vars.rpcMethod default "") }
}

%dw 2.0
output application/json
---
{
  tools: [
    {
      name: "get_quality_agreement",
      description: "サプライヤーの品質保証協定書サマリ(条項・ペナルティ上限)を取得する。",
      inputSchema: {
        "type": "object",
        properties: {
          supplierGoldenId: { "type": "string" },
          partNumber:       { "type": "string" }
        },
        required: ["supplierGoldenId"]
      }
    },
    {
      name: "generate_return_request",
      description: "返品要求書を生成する。requestId を返す。",
      inputSchema: {
        "type": "object",
        properties: {
          supplierGoldenId: { "type": "string" },
          partNumber:       { "type": "string" },
          incidentId:       { "type": "string" },
          quantity:         { "type": "integer" },
          reason:           { "type": "string" }
        },
        required: ["supplierGoldenId", "partNumber", "incidentId"]
      }
    },
    {
      name: "send_penalty_notice",
      description: "ペナルティ通知書を送付する。noticeId を返す。",
      inputSchema: {
        "type": "object",
        properties: {
          supplierGoldenId: { "type": "string" },
          incidentId:       { "type": "string" },
          amount:           { "type": "number" },
          currency:         { "type": "string" }
        },
        required: ["supplierGoldenId", "incidentId", "amount"]
      }
    }
  ]
}

