%dw 2.0
output application/json
import * from dw::core::Strings
var tool = (vars.toolName default "") as String
var inp = vars.toolInput default {}
var ts = now() as String {format: "yyyyMMddHHmmss"}
var rnd = (randomInt(9999) as String)
---
tool match {
  case "get_quality_agreement" -> {
    status: "success",
    tool: tool,
    result: {
      supplierGoldenId: (inp.supplierGoldenId default "") as String,
      partNumber:       (inp.partNumber default "") as String,
      agreementId:      "QA-2024-" ++ ((inp.supplierGoldenId default "GENERIC") as String),
      clause:           "§7.3",
      penaltyCap:       2500000,
      currency:         "JPY",
      summary:          "品質不良発生時の返品およびペナルティ条項。上限¥2,500,000。"
    }
  }
  case "generate_return_request" -> {
    status: "success",
    tool: tool,
    result: {
      requestId:        "RTN-" ++ ts ++ "-" ++ leftPad(rnd, 4, "0"),
      "status":         "GENERATED",
      supplierGoldenId: (inp.supplierGoldenId default "") as String,
      partNumber:       (inp.partNumber default "") as String,
      quantity:         ((inp.quantity default 0) as Number),
      incidentId:       (inp.incidentId default "") as String,
      reason:           (inp.reason default "") as String,
      generatedAt:      now() as String {format: "yyyy-MM-dd'T'HH:mm:ssXXX"}
    }
  }
  case "send_penalty_notice" -> {
    status: "success",
    tool: tool,
    result: {
      noticeId:         "PEN-" ++ ts ++ "-" ++ leftPad(rnd, 4, "0"),
      "status":         "SENT",
      supplierGoldenId: (inp.supplierGoldenId default "") as String,
      incidentId:       (inp.incidentId default "") as String,
      amount:           ((inp.amount default 0) as Number),
      currency:         ((inp.currency default "JPY") as String),
      sentAt:           now() as String {format: "yyyy-MM-dd'T'HH:mm:ssXXX"}
    }
  }
  else -> {
    status: "error",
    tool: tool,
    result: { code: "UNKNOWN_TOOL", message: "tool not supported: " ++ tool }
  }
}
